mapper.select:
SELECT CD_GROUP_ID1 AS expnsn_str_val1
     , CD_GROUP_ID2 AS expnsn_str_val2
     , DOC_VER
     , DOC_CONTENT
  FROM

SELECT CD_GROUP_ID1
     , CD_GROUP_ID2
     , DOC_VER
     , DOC_CONTENT
  FROM NMCP_FORM_DTL@DL_MCP
 WHERE CD_GROUP_ID1 = #{item.contentGroupCode}
   AND CD_GROUP_ID2 = #{item.contentItemCode}
   AND USE_YN = 'Y'

   AND DOC_TYPE = #{item.specType}


   AND EXPNSN_STR_VAL = #{item.specCode}

   AND doc_ver = (
                  SELECT max(doc_ver)
                    FROM NMCP_FORM_DTL@DL_MCP
                   WHERE CD_GROUP_ID1 = #{item.contentGroupCode}
                     AND CD_GROUP_ID2 = #{item.contentItemCode}
                     AND USE_YN = 'Y'

                     AND DOC_TYPE = #{item.specType}


                     AND EXPNSN_STR_VAL = #{item.specCode}

                 )
